import { _decorator, Component, director, Node, Label, Button, ProgressBar, Sprite, Toggle } from 'cc';
import { GameManager } from '../Core/GameManager';

const { ccclass, property } = _decorator;

@ccclass('EnhanceScene')
export class EnhanceScene extends Component {
    @property(Button)
    backBtn: Button = null;
    
    @property(Node)
    equipmentSlot: Node = null;
    
    @property(Label)
    equipmentNameLabel: Label = null;
    
    @property(Label)
    currentLevelLabel: Label = null;
    
    @property(Label)
    nextLevelLabel: Label = null;
    
    @property(Label)
    successRateLabel: Label = null;
    
    @property(Label)
    costLabel: Label = null;
    
    @property(Button)
    enhanceBtn: Button = null;
    
    @property(Button)
    autoEnhanceBtn: Button = null;
    
    @property(ProgressBar)
    enhanceProgress: ProgressBar = null;
    
    @property(Sprite)
    resultEffect: Sprite = null;
    
    // 当前选中的装备
    private selectedEquipment = {
        id: 'sword_001',
        name: '桃木拂尘',
        level: 0,
        maxLevel: 10,
        quality: 'rare'
    };
    
    // 强化配置
    private enhanceConfig = [
        { level: 0, cost: 1000, rate: 1.0, bonus: 0 },
        { level: 1, cost: 2000, rate: 0.95, bonus: 0.1 },
        { level: 2, cost: 4000, rate: 0.90, bonus: 0.2 },
        { level: 3, cost: 8000, rate: 0.85, bonus: 0.3 },
        { level: 4, cost: 15000, rate: 0.80, bonus: 0.4 },
        { level: 5, cost: 30000, rate: 0.75, bonus: 0.5 },
        { level: 6, cost: 60000, rate: 0.70, bonus: 0.6 },
        { level: 7, cost: 120000, rate: 0.65, bonus: 0.7 },
        { level: 8, cost: 250000, rate: 0.60, bonus: 0.8 },
        { level: 9, cost: 500000, rate: 0.55, bonus: 0.9 },
        { level: 10, cost: 1000000, rate: 0.50, bonus: 1.0 }
    ];
    
    onLoad() {
        this.backBtn.node.on(Button.EventType.CLICK, this.onBack, this);
        this.enhanceBtn.node.on(Button.EventType.CLICK, this.onEnhance, this);
        this.autoEnhanceBtn.node.on(Button.EventType.CLICK, this.onAutoEnhance, this);
    }
    
    start() {
        this.updateUI();
    }
    
    updateUI() {
        this.equipmentNameLabel.string = this.selectedEquipment.name;
        this.currentLevelLabel.string = `当前强化: +${this.selectedEquipment.level}`;
        
        if (this.selectedEquipment.level >= this.selectedEquipment.maxLevel) {
            this.nextLevelLabel.string = '已达到最高强化等级';
            this.successRateLabel.string = '-';
            this.costLabel.string = '-';
            this.enhanceBtn.interactable = false;
            this.autoEnhanceBtn.interactable = false;
        } else {
            const nextConfig = this.enhanceConfig[this.selectedEquipment.level + 1];
            this.nextLevelLabel.string = `下一级: +${this.selectedEquipment.level + 1}`;
            this.successRateLabel.string = `成功率: ${(nextConfig.rate * 100).toFixed(0)}%`;
            this.costLabel.string = `消耗: ${nextConfig.cost}香火钱`;
            this.enhanceBtn.interactable = true;
            this.autoEnhanceBtn.interactable = true;
        }
    }
    
    async onEnhance() {
        if (this.selectedEquipment.level >= this.selectedEquipment.maxLevel) return;
        
        const nextConfig = this.enhanceConfig[this.selectedEquipment.level + 1];
        const player = GameManager.getInstance().playerData;
        
        if (!player.costCurrency('incense_money', nextConfig.cost)) {
            console.log('香火钱不足');
            return;
        }
        
        // 播放强化动画
        this.enhanceBtn.interactable = false;
        await this.playEnhanceAnimation();
        
        // 判定成功失败
        const random = Math.random();
        if (random <= nextConfig.rate) {
            // 成功
            this.selectedEquipment.level++;
            this.showSuccessEffect();
            console.log(`强化成功！当前+${this.selectedEquipment.level}`);
        } else {
            // 失败（不掉级）
            this.showFailEffect();
            console.log('强化失败，装备未损坏');
        }
        
        this.enhanceBtn.interactable = true;
        this.updateUI();
    }
    
    async onAutoEnhance() {
        const targetLevel = Math.min(this.selectedEquipment.maxLevel, this.selectedEquipment.level + 3);
        
        while (this.selectedEquipment.level < targetLevel) {
            await this.onEnhance();
            await this.sleep(500);
        }
    }
    
    playEnhanceAnimation(): Promise<void> {
        return new Promise((resolve) => {
            let progress = 0;
            const interval = setInterval(() => {
                progress += 0.1;
                this.enhanceProgress.progress = progress;
                
                if (progress >= 1) {
                    clearInterval(interval);
                    this.enhanceProgress.progress = 0;
                    resolve();
                }
            }, 100);
        });
    }
    
    showSuccessEffect() {
        // 显示成功特效
        this.resultEffect.node.active = true;
        this.resultEffect.node.getChildByName('Label').getComponent(Label).string = '强化成功！';
        this.resultEffect.node.getChildByName('Label').getComponent(Label).color = {r: 0, g: 255, b: 0, a: 255};
        
        setTimeout(() => {
            this.resultEffect.node.active = false;
        }, 2000);
    }
    
    showFailEffect() {
        // 显示失败特效
        this.resultEffect.node.active = true;
        this.resultEffect.node.getChildByName('Label').getComponent(Label).string = '强化失败';
        this.resultEffect.node.getChildByName('Label').getComponent(Label).color = {r: 255, g: 0, b: 0, a: 255};
        
        setTimeout(() => {
            this.resultEffect.node.active = false;
        }, 2000);
    }
    
    sleep(ms: number): Promise<void> {
        return new Promise(resolve => setTimeout(resolve, ms));
    }
    
    onBack() {
        director.loadScene('MainScene');
    }
}
